import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"附加订单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/conditional-order.md","filePath":"zh-CN/stock-trading/order-types/conditional-order.md"}'),t={name:"stock-trading/order-types/conditional-order.md"};function o(d,a,n,h,s,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="附加订单" tabindex="-1">附加订单 <a class="header-anchor" href="#附加订单" aria-label="Permalink to &quot;附加订单&quot;">​</a></h1><p>附加订单是附加在一笔普通开仓订单之上的平仓订单，会在主订单完全成交并达到设置的触发价格后自动提交，用于止盈或止损，帮助控制交易风险。</p><h2 id="附加类型" tabindex="-1">附加类型 <a class="header-anchor" href="#附加类型" aria-label="Permalink to &quot;附加类型&quot;">​</a></h2><h3 id="止盈" tabindex="-1">止盈 <a class="header-anchor" href="#止盈" aria-label="Permalink to &quot;止盈&quot;">​</a></h3><p>当设置的止盈触发价满足条件时，系统自动提交一笔与主订单方向相反的订单：</p><ul><li>止盈市价单：以市价单平仓</li><li>止盈限价单：以止盈委托价的限价单平仓</li></ul><h3 id="止损" tabindex="-1">止损 <a class="header-anchor" href="#止损" aria-label="Permalink to &quot;止损&quot;">​</a></h3><p>当设置的止损触发价满足条件时，系统自动提交一笔与主订单方向相反的订单：</p><ul><li>止损市价单：以市价单平仓</li><li>止损限价单：以止损委托价的限价单平仓</li></ul><h3 id="括号单-止盈-止损" tabindex="-1">括号单（止盈 + 止损） <a class="header-anchor" href="#括号单-止盈-止损" aria-label="Permalink to &quot;括号单（止盈 + 止损）&quot;">​</a></h3><p>由一笔止盈单和一笔止损单共同组成。主订单完全成交后，先达到触发价的订单会被提交，另一笔订单自动撤销。</p><h2 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h2><h3 id="示例一-买入-括号单" tabindex="-1">示例一：买入 + 括号单 <a class="header-anchor" href="#示例一-买入-括号单" aria-label="Permalink to &quot;示例一：买入 + 括号单&quot;">​</a></h3><p>市场价格 10，提交买入限价单（价格 9.9，数量 100），附加括号单（市价），止盈触发价 12，止损触发价 9。</p><ol><li>市场价格 10 → 9.8，主订单以 9.9 完全成交，开始监控</li><li>市场价格 9.8 → 12，达到止盈触发价 → 下达卖出市价单止盈，止损单自动撤销</li></ol><h3 id="示例二-卖空-止损限价单" tabindex="-1">示例二：卖空 + 止损限价单 <a class="header-anchor" href="#示例二-卖空-止损限价单" aria-label="Permalink to &quot;示例二：卖空 + 止损限价单&quot;">​</a></h3><p>市场价格 10，提交卖空限价单（价格 10.1，数量 100），附加止损限价单，止损触发价 15，止损委托价 15。</p><ol><li>市场价格 10 → 16，主订单以 10.1 完全成交，开始监控</li><li>市场价格达到 15，触发止损 → 下达买入限价单（价格 15）止损</li></ol><h2 id="执行失败场景与仓位风险" tabindex="-1">执行失败场景与仓位风险 <a class="header-anchor" href="#执行失败场景与仓位风险" aria-label="Permalink to &quot;执行失败场景与仓位风险&quot;">​</a></h2><ul><li>主订单仅支持开仓，平仓时 APP 界面不会有附加单入口</li><li>附加订单在主订单完全成交并达到触发价后才进行风控检查，若未通过则所有附加订单执行失败</li><li>系统不会在主订单成交后冻结持仓。如其他交易导致持仓变化，子订单触发时可能因仓位不足而执行失败</li><li>止损/止盈市价单、括号单（市价）仅支持盘中交易，盘前盘后触发会预埋到盘中下单</li><li>止损/止盈限价单、括号单（限价）支持盘前盘后交易，但委托价格设置不合理可能无法及时止盈止损</li></ul>',20)])])}const _=e(t,[["render",o]]);export{p as __pageData,_ as default};
